import {useEffect, useState} from "react";
import {Calendar} from "primereact/calendar";
import type {FormEvent} from "primereact/ts-helpers";
import type {FilterEl} from "../Filter";

const DateFilterTemplate: FilterEl = (options) => {
  const isRange =
    typeof options.filterModel?.matchMode == "string" &&
    options.filterModel.matchMode == "between";

  const value =
    (!isRange && Array.isArray(options.value)) ||
    (isRange && !Array.isArray(options.value))
      ? null
      : options.value;

  const [selectedValue, setSelectedValue] = useState<any>(value);

  useEffect(() => {
    if (
      (isRange && Array.isArray(options.value)) ||
      (!isRange && !Array.isArray(options.value))
    ) {
      setSelectedValue(options.value);
    }
  }, [isRange, options.value]);

  // Function to adjust time for start and end of the day
  const adjustDateTime = (date: Date, isStart: boolean): Date => {
    if (!date) return date;
    const adjustedDate = new Date(date);
    if (isStart) {
      adjustedDate.setHours(0, 0, 0, 0); // Start of the day (00:00:00)
    } else {
      adjustedDate.setHours(23, 59, 59, 999); // End of the day (23:59:59)
    }
    return adjustedDate;
  };

  return (
    <Calendar
      id={"table-date-filter"}
      value={options.value ?? selectedValue}
      dateFormat="dd/mm/yy"
      placeholder={isRange ? "dd/mm/yyyy - dd/mm/yyyy" : "dd/mm/yyyy"}
      selectionMode={isRange ? "range" : "single"}
      view={"date"}
      numberOfMonths={isRange ? 3 : 1}
      onChange={(event: FormEvent<any>) => {
        let adjustedValue = event.value;
        if (isRange && Array.isArray(adjustedValue) && adjustedValue.length === 2) {
          adjustedValue = [
            adjustDateTime(adjustedValue[0], true),  // Start of the first day
            adjustDateTime(adjustedValue[1], false), // End of the second day
          ];
        } else if (!isRange && adjustedValue instanceof Date) {
          adjustedValue = adjustDateTime(adjustedValue, true); // Single date, set start of the day
        }

        options.filterApplyCallback(adjustedValue);
        setSelectedValue(adjustedValue);
      }}
    />
  );
};

export default DateFilterTemplate;
